# generate wide-format gof table across all models
generate_gof_table &lt;- function(gof_metrics) {
  table_df &lt;- purrr::map_dfc(gof_metrics, ~ combine_gof_metrics_summary(.x)$Formatted)
  metrics &lt;- combine_gof_metrics_summary(gof_metrics[[1]])$Metric
  table_df &lt;- cbind(Metric = metrics, table_df)
  colnames(table_df)[-1] &lt;- paste("Model", seq_along(gof_metrics) - 1)
  table_df
}




