1 Verify Dataset from Step 5


Code
# define expected variable structure
expected_vars &lt;- list(
  # respondent's own SES
  respondent = c("education_self", "isei08_self"),

  # parental SES (individual indicators)
  parental_individual = c(
    "education_father", "education_mother",
    "isei08_father", "isei08_mother"
  ),

  # parental SES (composites)
  parental_composites = c("education_parental", "isei08_parental"),

  # partner SES
  partner = c("education_partner", "isei08_partner"),

  # core analysis variables
  core = c("idnummer", "partner", "dhd_index", "dhd_kcal"),

  # reconciled robustness columns carried through steps 3 to 5
  robustness = c(
    "siops08", "siops08_father", "siops08_mother", "siops08_partner",
    "egp11", "egp11_father", "egp11_mother", "egp11_partner",
    "lf_status", "lf_status_father", "lf_status_mother", "lf_status_partner"
  )
)

# flatten for checking
all_expected &lt;- unlist(expected_vars, use.names = FALSE)



in: imputed_data (from Step 5)
out: imputed_data (canonical naming, composites verified)
rule: composites = row-mean of parental components with na.rm = FALSE, so the composite is NA when either parent is missing; the available-case alternative (na.rm = TRUE) is reserved for the step 5 sensitivity analysis



Code
# rename legacy occupation_* variables to isei08_* if present
# (temporary fix until upstream Step 5 is re-run with corrected code)
legacy_renames &lt;- c(
  "occupation_self" = "isei08_self",
  "occupation_father" = "isei08_father",
  "occupation_mother" = "isei08_mother",
  "occupation_partner" = "isei08_partner"
)

legacy_found &lt;- names(legacy_renames)[names(legacy_renames) %in% names(imputed_data)]
if (length(legacy_found) &gt; 0) {
  for (old_name in legacy_found) {
    new_name &lt;- legacy_renames[[old_name]]
    if (!new_name %in% names(imputed_data)) {
      names(imputed_data)[names(imputed_data) == old_name] &lt;- new_name
    }
  }
}

# identify present and missing expected variables
vars_present &lt;- all_expected[all_expected %in% names(imputed_data)]
vars_missing &lt;- setdiff(all_expected, vars_present)

# count observations by partner status
n_obs &lt;- nrow(imputed_data)
n_partnered &lt;- sum(imputed_data$partner == 1, na.rm = TRUE)
n_non_partnered &lt;- sum(imputed_data$partner == 0, na.rm = TRUE)

# check for any remaining legacy variable names
legacy_names &lt;- c(
  "parental_edu", "parental_occ", "partner_edu", "partner_occ",
  "occupation_self", "occupation_father", "occupation_mother", "occupation_partner"
)
legacy_present &lt;- legacy_names[legacy_names %in% names(imputed_data)]

# create or recreate parental composites to ensure consistent computation
# use na.rm = FALSE for complete-case means, consistent with step 3
composites_created &lt;- character(0)
composites_updated &lt;- character(0)

# education_parental: mean of father and mother education
if (all(c("education_father", "education_mother") %in% names(imputed_data))) {
  edu_new &lt;- rowMeans(
    imputed_data[, c("education_father", "education_mother")],
    na.rm = FALSE
  )
  # set to NA where both components are missing
  both_missing &lt;- is.na(imputed_data$education_father) &
    is.na(imputed_data$education_mother)
  edu_new[both_missing] &lt;- NA

  if (!"education_parental" %in% names(imputed_data)) {
    imputed_data$education_parental &lt;- edu_new
    composites_created &lt;- c(composites_created, "education_parental")
  } else if (!isTRUE(all.equal(imputed_data$education_parental, edu_new,
    tolerance = 1e-10, check.attributes = FALSE
  ))) {
    imputed_data$education_parental &lt;- edu_new
    composites_updated &lt;- c(composites_updated, "education_parental")
  }
}

# isei08_parental: mean of father and mother occupation
if (all(c("isei08_father", "isei08_mother") %in% names(imputed_data))) {
  occ_new &lt;- rowMeans(
    imputed_data[, c("isei08_father", "isei08_mother")],
    na.rm = FALSE
  )
  # set to NA where both components are missing
  both_missing &lt;- is.na(imputed_data$isei08_father) &
    is.na(imputed_data$isei08_mother)
  occ_new[both_missing] &lt;- NA

  if (!"isei08_parental" %in% names(imputed_data)) {
    imputed_data$isei08_parental &lt;- occ_new
    composites_created &lt;- c(composites_created, "isei08_parental")
  } else if (!isTRUE(all.equal(imputed_data$isei08_parental, occ_new,
    tolerance = 1e-10, check.attributes = FALSE
  ))) {
    imputed_data$isei08_parental &lt;- occ_new
    composites_updated &lt;- c(composites_updated, "isei08_parental")
  }
}

# re-check after creating/updating composites
vars_present &lt;- all_expected[all_expected %in% names(imputed_data)]
vars_missing &lt;- setdiff(all_expected, vars_present)

# generate verification report
verification_status &lt;- if (length(vars_missing) == 0 && length(legacy_present) == 0) {
  "&lt;span style='color: green;'&gt;&#x2714; All expected variables present&lt;/span&gt;"
} else if (length(legacy_present) &gt; 0) {
  glue(
    "&lt;span style='color: red;'&gt;&#x2718; Legacy variable names detected: ",
    "&lt;code&gt;{paste(legacy_present, collapse = '&lt;/code&gt;, &lt;code&gt;')}&lt;/code&gt;&lt;/span&gt;"
  )
} else {
  glue(
    "&lt;span style='color: orange;'&gt;&#x26A0; Missing expected variables: ",
