# create boxplot with outliers highlighted and confidence intervals
create_boxplot &lt;- function(data, variable, ids, mean_val, ci_lower, ci_upper) {
  # define colors
  ci_color &lt;- viridis::plasma(20)[4]
  outlier_color &lt;- viridis::plasma(20)[12]
