    "$^{\\ast\\ast\\ast}p \\leq 0.001$",
    "$^{\\ast\\ast}p \\leq 0.01$",
    "$^{\\ast}p \\leq 0.05$"
  )
  if (use_dot_for_0.1) {
    p_values &lt;- c(p_values, "$^{\\cdot}p \\leq 0.1$")
  }
  if (non_sig) {
    p_values &lt;- c(p_values, "$^{\\text{n.s.}}p &gt; 0.05$")
  }
  if (html) {
    p_values &lt;- md_to_html(p_values)
  }
  if (concatenate) {
    p_values &lt;- toString(p_values)
  }
  return(p_values)
}




