# ' @title Extract model formula
# ' @description Retrieves formula from model object, removes extraneous
# '   whitespace, preserves environment context
# ' @param model_object fitted model
# ' @return Cleaned formula object
get_formula &lt;- function(model_object) {
  f &lt;- formula(model_object)
  env &lt;- environment(f)

  formula_str &lt;- paste(deparse(f), collapse = "")
  clean_formula_str &lt;- gsub("\\s+", " ", formula_str)
